input.command:
ADMIN_PASS=$(kubectl get secret admin-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)
APP_PASS=$(kubectl get secret app-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)
READONLY_PASS=$(kubectl get secret readonly-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)

kubectl exec -n mongodb mongodb-replica-2 -- mongosh --quiet \
  "mongodb://admin-user:${ADMIN_PASS}@localhost:27017/admin" \
  --eval '
// 1. Create reportingRole on appdb allowing aggregate on appdb.reports
var adminDb = db.getSiblingDB("admin");
var appDb = db.getSiblingDB("appdb");

// Create reportingRole if it does not exist
try {
  appDb.createRole({
    role: "reportingRole",
    privileges: [
      {
        resource: { db: "appdb", collection: "reports" },
        actions: ["find", "aggregate"]
      }
    ],
    roles: []
  });
  print("reportingRole created");
